const OFFICE = { x: 670, y: 488 };

const COLORS: Record<string, { fill: string; active: string; stroke: string }> = {
  kazakhstan: { fill: "fill-sky-200/60", active: "fill-sky-300/80", stroke: "stroke-sky-400/40" },
  uzbekistan: { fill: "fill-primary/20", active: "fill-primary/40", stroke: "stroke-primary/35" },
  kyrgyzstan: {
    fill: "fill-emerald-200/60",
    active: "fill-emerald-300/80",
    stroke: "stroke-emerald-400/40",
  },
  tajikistan: {
    fill: "fill-violet-200/60",
    active: "fill-violet-300/80",
    stroke: "stroke-violet-400/40",
  },
  afghanistan: {
    fill: "fill-amber-200/60",
    active: "fill-amber-300/80",
    stroke: "stroke-amber-400/40",
  },
};

export function CentralAsiaMapSvg({
  ariaLabel,
  officeLabel,
}: {
  ariaLabel: string;
  officeLabel?: string;
}) {
  const [active, setActive] = useState<string | null>(null);

  return (
    <figure className="relative w-full">
      <svg
        viewBox="0 0 1200 900"
        className="h-auto max-h-[min(80vh,42rem)] w-full drop-shadow-sm"
        role="img"
        aria-label={ariaLabel}
        onMouseLeave={() => setActive(null)}
      >
        <defs>
          <linearGradient id="ca-bg" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="var(--color-surface-container-low)" />
            <stop offset="100%" stopColor="var(--color-primary-fixed)" stopOpacity="0.2" />
          </linearGradient>
          <filter id="ca-shadow" x="-50%" y="-50%" width="200%" height="200%">
            <feDropShadow dx="0" dy="1.5" stdDeviation="2" floodOpacity="0.15" />
          </filter>
        </defs>

        <rect width="1200" height="900" fill="url(#ca-bg)" rx="12" />

        {COUNTRIES.map((country) => {
          const isActive = active === country.id;
          const c = COLORS[country.id];
          if (!c) return null;
          return (
            <g
              key={country.id}
              transform={country.transform}
              onMouseEnter={() => setActive(country.id)}
              className="cursor-pointer"
            >
              {country.paths.map((d, i) => (
                <path
                  key={i}
                  d={d}
                  className={cn(
                    "stroke-[0.8] transition-[fill] duration-200",
                    isActive ? c.active : c.fill,
                    c.stroke,
                  )}
                  strokeLinejoin="round"
                />
              ))}
            </g>
          );
        })}

        {/* Toshkent office marker */}
        <g
          filter="url(#ca-shadow)"
          className="cursor-pointer"
          onMouseEnter={() => setActive("office")}
          onMouseLeave={() => setActive(null)}
        >
          <circle cx={OFFICE.x} cy={OFFICE.y} r={18} className="fill-tertiary/20" />
          <path
            d={`M ${OFFICE.x} ${OFFICE.y - 10} L ${OFFICE.x + 2.5} ${OFFICE.y - 2} L ${OFFICE.x + 10} ${OFFICE.y - 2} L ${OFFICE.x + 3.5} ${OFFICE.y + 2.5} L ${OFFICE.x + 6} ${OFFICE.y + 10} L ${OFFICE.x} ${OFFICE.y + 6} L ${OFFICE.x - 6} ${OFFICE.y + 10} L ${OFFICE.x - 3.5} ${OFFICE.y + 2.5} L ${OFFICE.x - 10} ${OFFICE.y - 2} L ${OFFICE.x - 2.5} ${OFFICE.y - 2} Z`}
            className="fill-tertiary stroke-white stroke-[1.5]"
          />
          <title>{officeLabel ?? "Verikore"}</title>
        </g>
      </svg>

      <figcaption className="font-label text-on-surface mt-3 min-h-[1.25rem] text-center text-sm font-bold">
        {active && active !== "office" ? (
          COUNTRIES.find((c) => c.id === active)?.label
        ) : active === "office" ? (
          (officeLabel ?? "Verikore")
        ) : (
          <span className="text-on-surface-variant font-normal">{ariaLabel}</span>
        )}
      </figcaption>
    </figure>
  );
}
